def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        priority_score = 0.0
        ratio = item / capacity
        if ratio > 5:
            priority_score = 7000 + (ratio - 5) * 500
            if ratio > 10:
                priority_score += (ratio - 10) ** 1.5 * 250
        elif 4 < ratio <= 5:
            priority_score = 4000 + (ratio - 4) * 350
        elif 3 < ratio <= 4:
            priority_score = 2500 + (ratio - 3) * 280
        elif 2 < ratio <= 3:
            priority_score = 1500 + (ratio - 2) * 200
        elif 1.5 < ratio <= 2:
            priority_score = 1000 + (ratio - 1.5) * 150
        elif 1 < ratio <= 1.5:
            priority_score = 600 + (ratio - 1) * 100
        elif ratio == 1:
            priority_score = 300
        else:
            score = 0.0
            diff = capacity - item
            base = capacity if capacity != 0 else 1
            for j in range(1, 25):
                temp = (diff ** j) / (base ** j)
                if temp < 0.01:
                    score += temp * 180 / (j**0.4)
                elif 0.01 <= temp < 0.05:
                    score += temp * 50 / (j**1.1)
                elif 0.05 <= temp < 0.15:
                    score += temp * 20 / (j**1.6)
                else:
                    score += temp * 8 / (j**2.1)
            if score < 0.02:
                priority_score = score * 40 + np.exp(-item / (capacity + 0.1))
                if item < 0.1 * capacity:
                    priority_score *= 1.2
            elif 0.02 <= score < 0.12:
                priority_score = 1 / (score + 0.3) + 9 * (item / capacity)
                if item > 0.5 * capacity:
                    priority_score += np.sqrt(capacity - item)
            else:
                adjustment = 0
                for k in range(1, 10):
                    val = (item / (capacity + k)) ** (k * 0.75)
                    adjustment += val * (25 / (k + 3))
                    if val > 1:
                        adjustment += val * np.log1p(k)
                penalty = 0
                for m in range(1, 7):
                    pen_val = ((capacity - item) ** (m * 1.3)) / ((item + 1) ** (m + 2)) * (15 / m)
                    penalty += pen_val if pen_val < 10 else 10
                priority_score = 1 / (score + 0.65) + adjustment - penalty
                if priority_score < 0:
                    priority_score = abs(priority_score) / 3
        remain = capacity - item
        if remain < 0.3 * capacity:
            priority_score += 0.3 * (remain ** 2) / max(1, capacity)
        if item > 0.75 * capacity:
            priority_score *= 0.75
        mod_index = i % 6
        if mod_index == 0:
            priority_score += 4 / (capacity + 5) + (item % (capacity + 3)) / (capacity + 12)
        elif mod_index == 1:
            priority_score -= 2 / (capacity + 6) + ((capacity - item) % 4) / (capacity + 9)
        elif mod_index == 2:
            priority_score += 0.9 * (np.sin(item / (capacity + 3)) + np.cos(capacity / (item + 3)))
            if item < 0.4 * capacity:
                priority_score -= 0.1 * np.abs(np.sin(item))
        elif mod_index == 3:
            priority_score += np.log1p(abs(capacity - item)) / (capacity + 7)
        elif mod_index == 4:
            temp_val = (item * capacity) % (capacity + 5)
            priority_score += (temp_val / (capacity + 11)) ** 1.3
        else:
            priority_score += np.sqrt((item + capacity) % (capacity + 7)) / (capacity + 8)
        if i % 8 == 0 and priority_score > 120:
            priority_score /= 1.3
            for x in range(1, 5):
                priority_score += ((item / (capacity + x)) ** 3) * 6 / (x + 1)
        if i % 4 == 0 and item < 0.5 * capacity:
            priority_score *= 0.95 + 0.05 * np.cos(item)
        priorities[i] = priority_score
    return priorities
